"use client"

import { useEffect, useState } from "react"
import Link from "next/link"

export default function ExecutionList() {
  const [data, setData] = useState<any[]>([])

  useEffect(() => {
    fetch("/api/execution/properties")
      .then(res => res.json())
      .then(setData)
  }, [])

  return (
    <div>
      <h1>Execution Workspace</h1>
      {data.map(p => (
        <div key={p._id}>
          {p.address} —
          <Link href={`/execution/${p._id}`}> Open</Link>
        </div>
      ))}
    </div>
  )
}
